  /// Load inspection data from SQLite (offline-first)
  Future<void> _loadInspectionData() async {
    final database = InspectionProvider.instance.database;
    if (database == null) {
      throw Exception('Database not initialized');
    }

    // Load inspection metadata from SQLite
    final inspectionResults = await database.query(
      'inspections',
      where: 'id = ?',
      whereArgs: [_inspectionId],
    );

    if (inspectionResults.isEmpty) {
      throw Exception('Inspection not found: $_inspectionId');
    }

    final inspection = inspectionResults.first;
    final templateId = inspection['template_id'] as String;

    // Load template name to display as unit name
    final templateResults = await database.query(
      'template_versions',
      where: 'template_id = ?',
      whereArgs: [templateId],
      limit: 1,
    );

    if (templateResults.isNotEmpty) {
      final schemaJson = jsonDecode(templateResults.first['schema_json'] as String);
      _unitName = schemaJson['name'] as String? ?? 'Unknown Unit';
    }

    // Load existing field values
    final valueResults = await database.query(
      'inspection_values',
      where: 'inspection_id = ?',
      whereArgs: [_inspectionId],
    );

    for (final row in valueResults) {
      final fieldId = row['field_id'] as String;
      final valueJson = row['value_json'] as String?;
      if (valueJson != null) {
        final value = jsonDecode(valueJson);
        _fieldValues[fieldId] = FieldValue(
