// START of Epic A (Core Mobile Inspection Workflow), Story A.5:implementation: Mobile Annotation System (Photos & Diagrams) | As a field technician I want to annotate engineering diagrams and photos directly on my mobile device while offline so that I can mark defect locations and measurements in real-time without network connectivity.

enum AnnotationLayer { mobile, web, admin }

enum AnnotationToolType { arrow, circle, line, freehand, text, eraser }

enum AnnotationTargetType { photo, diagram }

/// Domain model representing an annotation persisted locally and synced to backend.
class Annotation {
  final String id;
  final String targetId;
  final AnnotationTargetType targetType;
  final AnnotationLayer layer;
  final AnnotationToolType toolType;
  final UnmodifiableListView<double> coordinates;
  final String strokeColor;
  final double strokeWidth;
  final String? text;
  final String? createdByUserId;
  final DateTime createdAt;
  final DateTime? syncedAt;
  final SyncStatus syncStatus;

  Annotation({
    required this.id,
    required String targetId,
    this.targetType = AnnotationTargetType.photo,
    required this.layer,
    required this.toolType,
    required List<double> coordinates,
    required this.strokeColor,
    this.strokeWidth = 2.0,
    this.text,
    this.createdByUserId,
    required this.createdAt,
    this.syncedAt,
    this.syncStatus = SyncStatus.pending,
  })  : targetId = targetId,
        coordinates = UnmodifiableListView<double>(coordinates);

  /// Legacy accessor retained for compatibility with Drift schema column name.
  String get photoId => targetId;

  /// Encodes structured annotation details to JSON for storage.
  String get annotationDataJson => jsonEncode(<String, dynamic>{
        'toolType': toolType.name,
        'coordinates': coordinates.toList(growable: false),
        'strokeColor': strokeColor,
        'strokeWidth': strokeWidth,
        'text': text,
        'createdByUserId': createdByUserId,
        'targetType': targetType.name,
      });

  /// Creates a domain annotation from Drift row values.
  factory Annotation.fromDatabase({
    required String id,
    required String targetId,
    required String layer,
    required String annotationDataJson,
    required int createdAt,
    required String syncStatus,
    int? syncedAt,
  }) {
    final decoded = jsonDecode(annotationDataJson) as Map<String, dynamic>;
    return Annotation(
      id: id,
      targetId: targetId,
      layer: AnnotationLayer.values.firstWhere((value) => value.name == layer, orElse: () => AnnotationLayer.mobile),
      toolType: AnnotationToolType.values.firstWhere((value) => value.name == (decoded['toolType'] as String? ?? 'arrow'), orElse: () => AnnotationToolType.arrow),
      coordinates: ((decoded['coordinates'] as List<dynamic>? ?? <dynamic>[])).map((value) => (value as num).toDouble()).toList(),
      strokeColor: decoded['strokeColor'] as String? ?? '#FF0000',
      strokeWidth: (decoded['strokeWidth'] as num?)?.toDouble() ?? 2.0,
      text: decoded['text'] as String?,
      createdByUserId: decoded['createdByUserId'] as String?,
      targetType: AnnotationTargetType.values.firstWhere(
        (value) => value.name == (decoded['targetType'] as String? ?? AnnotationTargetType.photo.name),
        orElse: () => AnnotationTargetType.photo,
      ),
      createdAt: DateTime.fromMillisecondsSinceEpoch(createdAt, isUtc: true),
      syncedAt: syncedAt != null ? DateTime.fromMillisecondsSinceEpoch(syncedAt, isUtc: true) : null,
      syncStatus: SyncStatus.values.firstWhere((value) => value.name == syncStatus, orElse: () => SyncStatus.pending),
    );
  }

  Annotation copyWith({
    String? id,
    String? targetId,
    AnnotationTargetType? targetType,
    AnnotationLayer? layer,
    AnnotationToolType? toolType,
    List<double>? coordinates,
    String? strokeColor,
    double? strokeWidth,
    String? text,
    String? createdByUserId,
    DateTime? createdAt,
    DateTime? syncedAt,
    SyncStatus? syncStatus,
  }) {
    return Annotation(
      id: id ?? this.id,
      targetId: targetId ?? this.targetId,
      targetType: targetType ?? this.targetType,
      layer: layer ?? this.layer,
      toolType: toolType ?? this.toolType,
      coordinates: coordinates ?? this.coordinates,
      strokeColor: strokeColor ?? this.strokeColor,
      strokeWidth: strokeWidth ?? this.strokeWidth,
      text: text ?? this.text,
      createdByUserId: createdByUserId ?? this.createdByUserId,
      createdAt: createdAt ?? this.createdAt,
      syncedAt: syncedAt ?? this.syncedAt,
      syncStatus: syncStatus ?? this.syncStatus,
    );
  }

  bool get isMobileLayer => layer == AnnotationLayer.mobile;
}

